var ErrEmpty = errors.New("empty input")

// Average returns the mean of xs, or ErrEmpty rather than NaN for empty input.
func Average(xs []float64) (float64, error) {
	if len(xs) == 0 {
		return 0, ErrEmpty
	}
	var s float64
	for _, x := range xs {
		s += x
	}
